// JWT Token Validation - v2.0.0
// v2.0.0: Fetch JWT_SECRET from app_config
const webhookData = $('POST Add Destination - Webhook').first().json;
const jwtSecret = $('Get JWT Secret - Supabase').first().json.value;

if (!jwtSecret) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'JWT secret not configured',
      statusCode: 500,
      timestamp: new Date().toISOString()
    }
  }];
}

const authHeader = webhookData.headers?.authorization || webhookData.headers?.Authorization;

if (!authHeader) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Missing authorization header',
      statusCode: 401,
      timestamp: new Date().toISOString()
    }
  }];
}

if (!authHeader.startsWith('Bearer ')) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Invalid authorization format',
      statusCode: 401,
      timestamp: new Date().toISOString()
    }
  }];
}

const token = authHeader.substring(7);

function simpleHash(input) {
  let hash = 0;
  for (let i = 0; i < input.length; i++) {
    const char = input.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return hash.toString(36);
}

function verifyJWT(token, secret) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) {
      return { valid: false, error: 'Invalid token format' };
    }
    const [header, payload, sig] = parts;
    const expected = simpleHash(`${header}.${payload}.${secret}`);
    if (sig !== expected) {
      return { valid: false, error: 'Invalid token signature' };
    }
    const decoded = JSON.parse(atob(payload));
    const now = Math.floor(Date.now() / 1000);
    if (decoded.exp && decoded.exp < now) {
      return { valid: false, error: 'Token expired' };
    }
    return { valid: true, payload: decoded };
  } catch (e) {
    return { valid: false, error: 'Token verification failed' };
  }
}

const result = verifyJWT(token, jwtSecret);

if (!result.valid) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: result.error || 'Invalid token',
      statusCode: 401,
      timestamp: new Date().toISOString()
    }
  }];
}

const p = result.payload;

if (p.type === 'limited') {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Full authentication required',
      statusCode: 403,
      timestamp: new Date().toISOString()
    }
  }];
}

if (p.type === 'refresh') {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Refresh tokens cannot be used here',
      statusCode: 403,
      timestamp: new Date().toISOString()
    }
  }];
}

const allowedRoles = ['admin', 'supervisor'];
if (!allowedRoles.includes(p.role)) {
  return [{
    json: {
      _route: 'unauthorized',
      success: false,
      message: 'Insufficient permissions',
      statusCode: 403,
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    _route: 'authorized',
    authenticated: true,
    user: {
      id: p.user_id || null,
      username: p.sub,
      role: p.role,
      tokenType: p.type
    },
    requestBody: webhookData.body,
    timestamp: new Date().toISOString()
  }
}];
// v2.0.0 - Dynamic JWT secret + RBAC

// Validate Destination Data - v2.0.0
// v2.0.0: Async version with user context
const data = $json.requestBody || {};
const user = $('JWT Validation - Code').first().json.user;
const errors = [];

if (!data.name || data.name.trim() === '') {
  errors.push('Name is required');
}
if (!data.address || data.address.trim() === '') {
  errors.push('Address is required');
}
if (!data.city || data.city.trim() === '') {
  errors.push('City is required');
}
if (!data.province || data.province.trim() === '') {
  errors.push('Province is required');
}
if (!data.postal_code || data.postal_code.trim() === '') {
  errors.push('Postal code is required');
}

if (data.email && data.email.trim() !== '') {
  if (!data.email.includes('@')) {
    errors.push('Invalid email format');
  }
}

let parsedContacts = null;
if (data.contacts !== undefined && data.contacts !== null) {
  if (typeof data.contacts === 'string') {
    try {
      parsedContacts = JSON.parse(data.contacts);
    } catch (e) {
      errors.push('Contacts must be valid JSON');
    }
  } else {
    parsedContacts = data.contacts;
  }
  if (parsedContacts !== null && !Array.isArray(parsedContacts)) {
    errors.push('Contacts must be an array');
  }
}

if (errors.length > 0) {
  return [{
    json: {
      success: 'false',
      errors: errors,
      message: 'Validation failed: ' + errors.join(', '),
      skipSupabase: true
    }
  }];
}

const contacts = parsedContacts || [];
const destination = {
  name: data.name.trim(),
  address: data.address.trim(),
  city: data.city.trim(),
  province: data.province.trim().toUpperCase(),
  postal_code: data.postal_code.trim().toUpperCase(),
  phone: data.phone ? data.phone.trim() : null,
  email: data.email ? data.email.trim().toLowerCase() : null,
  contacts: contacts,
  notes: data.notes ? data.notes.trim() : null,
  active: data.active !== undefined ? data.active : true
};

if (!destination.phone && contacts.length > 0 && contacts[0].phone) {
  destination.phone = contacts[0].phone.trim();
}
if (!destination.email && contacts.length > 0 && contacts[0].email) {
  destination.email = contacts[0].email.trim().toLowerCase();
}

return [{
  json: {
    success: 'true',
    destination: destination,
    userId: user?.id || null,
    userName: user?.username || 'unknown',
    userRole: user?.role || 'unknown'
  }
}];
// v2.0.0 - Async version with user context

// Prepare Tasks and Branches - v2.0.0
// v2.0.0: Skip async for inactive destinations
const mergedInput = $input.all().map(item => item.json);
const validData = $('Validate Destination Data - Code').first().json;

const destination = mergedInput.find(item =>
  item.id !== undefined && item.name !== undefined && item.address !== undefined
);

if (!destination || !destination.id) {
  return [{
    json: {
      branchError: 'true',
      errorMessage: 'Destination creation failed'
    }
  }];
}

// QA item 6: skip distance calc for inactive destinations
const isActive = destination.active !== false;

const clients = mergedInput.filter(item =>
  item.knumber !== undefined && item.civicaddress !== undefined
);

const drivers = mergedInput.filter(item =>
  item.home_address !== undefined && !item.knumber && !item.address
);

const destAddress = [
  destination.address, destination.city,
  destination.province, destination.postal_code
].filter(Boolean).join(', ');

const destLabel = destination.name + ' (' + destAddress + ')';

return [{
  json: {
    destination: destination,
    destinationId: destination.id,
    destinationName: destination.name,
    destAddress: destAddress,
    destLabel: destLabel,
    clients: isActive ? clients : [],
    drivers: isActive ? drivers : [],
    skipAsync: isActive ? 'false' : 'true',
    userId: validData.userId,
    userName: validData.userName,
    userRole: validData.userRole
  }
}];
// v2.0.0 - Skip async for inactive destinations

// Collect Task IDs - v1.0.0
const taskItems = $input.all().map(item => item.json);
const branchData = $('Prepare Tasks and Branches - Code').first().json;

const taskMap = {};
taskItems.forEach(task => {
  if (task.task_type && task.id) {
    taskMap[task.task_type] = task.id;
  }
});

return [{
  json: {
    ...branchData,
    taskIds: taskMap
  }
}];
// v1.0.0 - Collect task IDs

// Format Async Response - v1.0.0
const input = $input.first().json;
const dest = input.destination;

if (!dest || dest.error) {
  return [{
    json: {
      success: false,
      message: 'Database error: ' + (dest?.error || 'Unknown'),
      data: null,
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    success: true,
    message: 'Destination created. Background tasks started.',
    data: {
      destination: dest,
      backgroundTasks: input.taskIds || {}
    },
    timestamp: new Date().toISOString()
  }
}];
// v1.0.0 - Async response with task IDs

// Format Error Response - v1.0.0
const errorData = $input.first().json;

return [{
  json: {
    success: false,
    message: errorData.message || 'Validation failed',
    errors: errorData.errors || [],
    timestamp: new Date().toISOString()
  }
}];
// v1.0.0 - Validation error response

// Unauthorized Response - v1.0.0
const data = $input.first().json;

return [{
  json: {
    success: false,
    message: data.message || 'Unauthorized',
    statusCode: data.statusCode || 401,
    timestamp: new Date().toISOString()
  }
}];
// v1.0.0 - Unauthorized error response

// Branch A: Prepare Distance Requests (Batched) - v1.0.0
// Batches up to 25 origins per Maps API call
const data = $input.first().json;
const apiKey = $('Get Maps API Key - Supabase').first().json.value;
const taskId = data.taskIds.calculate_distances;

if (!apiKey) {
  console.error('Google Maps API key not found');
  return [{
    json: {
      taskId: taskId,
      branchError: 'true',
      errorMessage: 'Google Maps API key not found'
    }
  }];
}

const destAddr = data.destAddress;
const BATCH_SIZE = 25;

// Build individual request metadata
const allReqs = [];

// Client → destination distances
data.clients.forEach(client => {
  const priAddr = [
    client.civicaddress, client.city,
    client.prov, client.postalcode
  ].filter(Boolean).join(', ');
  if (!priAddr) return;

  allReqs.push({
    type: 'client_destination',
    entityId: client.id,
    destinationId: data.destinationId,
    origin: priAddr,
    addressType: 'primary'
  });

  if (client.secondary_civic_address) {
    const secAddr = [
      client.secondary_civic_address,
      client.secondary_city,
      client.secondary_province,
      client.secondary_postal_code
    ].filter(Boolean).join(', ');
    if (secAddr) {
      allReqs.push({
        type: 'client_destination',
        entityId: client.id,
        destinationId: data.destinationId,
        origin: secAddr,
        addressType: 'secondary'
      });
    }
  }
});

// Driver → destination distances
data.drivers.forEach(driver => {
  if (!driver.home_address) return;
  allReqs.push({
    type: 'driver_destination',
    entityId: driver.id,
    destinationId: data.destinationId,
    origin: driver.home_address,
    addressType: 'primary'
  });
});

if (allReqs.length === 0) {
  return [{
    json: {
      taskId: taskId,
      branchError: 'true',
      errorMessage: 'No distances to calculate'
    }
  }];
}

// Batch into groups of BATCH_SIZE
const batches = [];
for (let i = 0; i < allReqs.length; i += BATCH_SIZE) {
  const batch = allReqs.slice(i, i + BATCH_SIZE);
  const origins = batch.map(r => r.origin).join('|');
  batches.push({
    json: {
      origins: origins,
      destinations: destAddr,
      apiKey: apiKey,
      taskId: taskId,
      batchMeta: batch,
      batchIndex: Math.floor(i / BATCH_SIZE)
    }
  });
}

return batches;
// v1.0.0 - Batched distance requests (25 per call)

// Branch A: Process Batch Results - v2.0.0
// v2.0.0: Add hasResults flag for delete-after-success pattern
const results = $input.all();
const origBatches = $('Branch A: Prepare Distances - Code').all();
const taskId = origBatches[0]?.json?.taskId;

if (origBatches[0]?.json?.branchError === 'true') {
  return [{
    json: {
      hasResults: 'false',
      tableType: 'error',
      taskId: taskId,
      errorMessage: origBatches[0].json.errorMessage
    }
  }];
}

const cdMap = {};
const ddMap = {};

results.forEach((result, batchIdx) => {
  const batch = origBatches[batchIdx]?.json;
  if (!batch || !batch.batchMeta) return;
  const meta = batch.batchMeta;
  const rows = result.json.rows || [];

  rows.forEach((row, rowIdx) => {
    const req = meta[rowIdx];
    if (!req) return;
    const el = row.elements?.[0];
    let distKm = null;
    let durMin = null;
    if (el && el.status === 'OK') {
      distKm = parseFloat((el.distance.value / 1000).toFixed(2));
      durMin = Math.ceil(el.duration.value / 60);
    }

    if (req.type === 'client_destination') {
      const k = req.entityId + '_' + req.destinationId;
      if (!cdMap[k]) {
        cdMap[k] = {
          client_id: req.entityId,
          destination_id: req.destinationId
        };
      }
      if (req.addressType === 'primary') {
        cdMap[k].primary_distance_km = distKm;
        cdMap[k].primary_duration_minutes = durMin;
      } else {
        cdMap[k].secondary_distance_km = distKm;
        cdMap[k].secondary_duration_minutes = durMin;
      }
    } else if (req.type === 'driver_destination') {
      const k = req.entityId + '_' + req.destinationId;
      ddMap[k] = {
        driver_id: req.entityId,
        destination_id: req.destinationId,
        distance_km: distKm,
        duration_minutes: durMin
      };
    }
  });
});

const now = new Date().toISOString();
const outputs = [];

Object.values(cdMap).forEach(rec => {
  outputs.push({
    json: {
      hasResults: 'true',
      tableType: 'client_destination',
      taskId: taskId,
      client_id: rec.client_id,
      destination_id: rec.destination_id,
      primary_distance_km: rec.primary_distance_km,
      primary_duration_minutes: rec.primary_duration_minutes,
      secondary_distance_km: rec.secondary_distance_km || null,
      secondary_duration_minutes: rec.secondary_duration_minutes || null,
      calculated_at: now,
      calculation_source: 'google_maps'
    }
  });
});

Object.values(ddMap).forEach(rec => {
  outputs.push({
    json: {
      hasResults: 'true',
      tableType: 'driver_destination',
      taskId: taskId,
      driver_id: rec.driver_id,
      destination_id: rec.destination_id,
      distance_km: rec.distance_km,
      duration_minutes: rec.duration_minutes,
      calculated_at: now,
      calculation_source: 'google_maps'
    }
  });
});

if (outputs.length === 0) {
  return [{ json: { hasResults: 'false', tableType: 'none', taskId: taskId } }];
}

return outputs;
// v2.0.0 - Add hasResults flag, delete-after-success

// Restore Distance Data - v1.0.0
// Delete nodes lose input; re-read from Process Results
return $('Branch A: Process Results - Code').all();
// v1.0.0 - Restore data after delete

// Branch A: Mark Task Status - v2.0.0
// v2.0.0: Handle no-results path from Has Results Switch
const allResults = $input.all();
const prepNode = $('Branch A: Prepare Distances - Code').first().json;
const taskId = prepNode.taskId;
const firstInput = allResults[0]?.json || {};

// Error path: branchError from Prepare node or error from Process Results
if (prepNode.branchError === 'true' || firstInput.tableType === 'error') {
  const errMsg = firstInput.errorMessage || prepNode.errorMessage || 'Unknown error';
  return [{
    json: {
      taskId: taskId,
      status: 'failed',
      error_message: errMsg,
      completed_at: new Date().toISOString(),
      result: JSON.stringify({ error: errMsg }),
      branch: 'A'
    }
  }];
}

// No results path (Maps returned no usable data)
if (firstInput.hasResults === 'false' || firstInput.tableType === 'none') {
  return [{
    json: {
      taskId: taskId,
      status: 'completed',
      error_message: null,
      completed_at: new Date().toISOString(),
      result: JSON.stringify({ distances_inserted: 0, note: 'No results from Maps API' }),
      branch: 'A'
    }
  }];
}

// Success path: items came through delete+insert
return [{
  json: {
    taskId: taskId,
    status: 'completed',
    error_message: null,
    completed_at: new Date().toISOString(),
    result: JSON.stringify({
      distances_inserted: allResults.length
    }),
    branch: 'A'
  }
}];
// v2.0.0 - Handle no-results + error paths

// Branch B: Prepare Travel Time Requests (Batched) - v1.0.0
// Calculates travel times from all clients to new destination
// Batches up to 25 client addresses per Maps API call
const data = $input.first().json;
const apiKey = $('Get Maps API Key - Supabase').first().json.value;
const taskId = data.taskIds.calculate_travel_times;

if (!apiKey) {
  console.error('Google Maps API key not found');
  return [{
    json: {
      taskId: taskId,
      branchError: 'true',
      errorMessage: 'Google Maps API key not found'
    }
  }];
}

const destAddr = data.destAddress;
const destName = data.destinationName;
const destId = data.destinationId;
const BATCH_SIZE = 25;

const allReqs = [];

data.clients.forEach(client => {
  const priAddr = [
    client.civicaddress, client.city,
    client.prov, client.postalcode
  ].filter(Boolean).join(', ');
  if (!priAddr) return;

  allReqs.push({
    clientId: client.id,
    knumber: client.knumber,
    clientAddress: priAddr,
    addressType: 'primary'
  });

  if (client.secondary_civic_address) {
    const secAddr = [
      client.secondary_civic_address,
      client.secondary_city,
      client.secondary_province,
      client.secondary_postal_code
    ].filter(Boolean).join(', ');
    if (secAddr) {
      allReqs.push({
        clientId: client.id,
        knumber: client.knumber,
        clientAddress: secAddr,
        addressType: 'secondary'
      });
    }
  }
});

if (allReqs.length === 0) {
  return [{
    json: {
      taskId: taskId,
      branchError: 'true',
      errorMessage: 'No clients for travel times'
    }
  }];
}

const batches = [];
for (let i = 0; i < allReqs.length; i += BATCH_SIZE) {
  const batch = allReqs.slice(i, i + BATCH_SIZE);
  const origins = batch.map(r => r.clientAddress).join('|');
  batches.push({
    json: {
      origins: origins,
      destinations: destAddr,
      apiKey: apiKey,
      taskId: taskId,
      destinationName: destName,
      destinationId: destId,
      batchMeta: batch,
      batchIndex: Math.floor(i / BATCH_SIZE)
    }
  });
}

return batches;
// v1.0.0 - Batched travel time requests

// Branch B: Aggregate Travel Times - v1.0.0
// Processes batched results into per-client travel times
const mapsResults = $input.all();
const origBatches = $('Branch B: Prepare Requests - Code').all();
const taskId = origBatches[0]?.json?.taskId;
const destName = origBatches[0]?.json?.destinationName;

if (origBatches[0]?.json?.branchError === 'true') {
  return [{
    json: {
      taskId: taskId,
      branchError: 'true',
      errorMessage: origBatches[0].json.errorMessage
    }
  }];
}

// Group results by clientId
const clientTravelTimes = {};
let successCount = 0;
let failCount = 0;

mapsResults.forEach((result, batchIdx) => {
  const batch = origBatches[batchIdx]?.json;
  if (!batch || !batch.batchMeta) return;
  const meta = batch.batchMeta;
  const rows = result.json.rows || [];

  rows.forEach((row, rowIdx) => {
    const req = meta[rowIdx];
    if (!req) return;
    const el = row.elements?.[0];
    const cid = req.clientId;
    const addr = req.addressType;

    if (!clientTravelTimes[cid]) {
      clientTravelTimes[cid] = { clientId: cid };
    }

    if (el && el.status === 'OK') {
      const rawMin = Math.ceil(el.duration.value / 60);
      const durMin = Math.ceil((rawMin + 5) / 5) * 5;
      const distKm = parseFloat(
        (el.distance.value / 1000).toFixed(2)
      );
      clientTravelTimes[cid][addr] = {
        duration_minutes: durMin,
        distance_km: distKm,
        calculated_at: new Date().toISOString()
      };
      successCount++;
    } else {
      clientTravelTimes[cid][addr] = {
        duration_minutes: null,
        distance_km: null,
        calculated_at: new Date().toISOString(),
        error: 'Maps API failed'
      };
      failCount++;
    }
  });
});

if (failCount > 0) {
  console.error('Branch B: ' + failCount + ' travel time calcs failed');
}

// Emit one item per client for update
const outputs = Object.values(clientTravelTimes).map(ct => ({
  json: {
    clientId: ct.clientId,
    destName: destName,
    travelData: ct,
    taskId: taskId
  }
}));

if (outputs.length === 0) {
  return [{
    json: {
      taskId: taskId,
      branchError: 'true',
      errorMessage: 'No travel times calculated'
    }
  }];
}

// Add summary as first item metadata
outputs[0].json.successCount = successCount;
outputs[0].json.failCount = failCount;

return outputs;
// v1.0.0 - Aggregate batched travel times

// Branch B: Prepare Merge - v1.1.0
// Extracts travel time data for merge in next node
const item = $input.first().json;
const clientId = item.clientId;
const destName = item.destName;
const td = item.travelData;

const newEntry = {};
if (td.primary) newEntry.primary = td.primary;
if (td.secondary) newEntry.secondary = td.secondary;

return [{
  json: {
    clientId: clientId,
    destName: destName,
    newTravelEntry: newEntry,
    taskId: item.taskId,
    successCount: item.successCount || 0,
    failCount: item.failCount || 0
  }
}];
// v1.1.0 - Removed dead httpRequest code

// Branch B: Merge Travel Times - v1.0.0
// Merges new destination travel time into client JSONB
const prepData = $('Branch B: Prepare Merge - Code').first().json;
const client = $input.first().json;
const destName = prepData.destName;
const newEntry = prepData.newTravelEntry;

let travelTimes = client.clinic_travel_times || {};
if (typeof travelTimes === 'string') {
  try { travelTimes = JSON.parse(travelTimes); }
  catch(e) { travelTimes = {}; }
}

travelTimes[destName] = {
  ...(travelTimes[destName] || {}),
  ...newEntry
};

return [{
  json: {
    clientId: prepData.clientId,
    mergedTravelTimes: travelTimes,
    taskId: prepData.taskId,
    successCount: prepData.successCount || 0,
    failCount: prepData.failCount || 0
  }
}];
// v1.0.0 - Merge travel times into JSONB

// Branch B: Mark Task Status - v1.0.0
const aggData = $('Branch B: Aggregate Travel Times - Code').first().json;
const taskId = aggData.taskId;

if (aggData.branchError === 'true') {
  return [{
    json: {
      taskId: taskId,
      status: 'failed',
      error_message: aggData.errorMessage,
      completed_at: new Date().toISOString(),
      result: JSON.stringify({ error: aggData.errorMessage }),
      branch: 'B'
    }
  }];
}

const sc = aggData.successCount || 0;
const fc = aggData.failCount || 0;

return [{
  json: {
    taskId: taskId,
    status: 'completed',
    error_message: null,
    completed_at: new Date().toISOString(),
    result: JSON.stringify({
      clients_updated: sc,
      failed: fc
    }),
    branch: 'B'
  }
}];
// v1.0.0 - Mark travel times task status

// Update Driver Clinic Preferences - v1.0.0
// Merge new destination distances into driver clinic_preferences
// New destinations default to preferred: false
const branchData = $('Prepare Tasks and Branches - Code').first().json;
const destId = String(branchData.destinationId);
const drivers = branchData.drivers;

// Get driver_destination_distances for this destination
const ddResults = $('Branch A: Process Results - Code').all()
  .filter(item => item.json.tableType === 'driver_destination');

const ddMap = {};
ddResults.forEach(item => {
  const d = item.json;
  ddMap[String(d.driver_id)] = {
    distance_km: d.distance_km,
    duration_minutes: d.duration_minutes
  };
});

// Build update items for each driver that has preferences
const outputs = [];

drivers.forEach(driver => {
  let prefs = driver.clinic_preferences || {};
  if (typeof prefs === 'string') {
    try { prefs = JSON.parse(prefs); }
    catch(e) { prefs = {}; }
  }

  // Only update drivers that have explicit preferences
  // Empty {} means "all clinics" — no update needed
  if (Object.keys(prefs).length === 0) return;

  const dd = ddMap[String(driver.id)] || {};
  prefs[destId] = {
    preferred: false,
    distance_km: dd.distance_km || null,
    drive_time_min: dd.duration_minutes || null
  };

  outputs.push({
    json: {
      driverId: driver.id,
      clinic_preferences: prefs
    }
  });
});

if (outputs.length === 0) {
  return [{
    json: {
      skipDriverUpdate: 'true',
      message: 'No drivers have explicit preferences'
    }
  }];
}

return outputs;
